import 'message.dart';
import 'varint.dart';

List<int> encodeEnvelope(Message message) {
  final payload = utf8.encode(jsonEncode(message.toJson()));
  return <int>[...encodeVarint(payload.length), ...payload];
}

List<Message> decodeEnvelopes(List<int> bytes) {
  final messages = <Message>[];
  var cursor = 0;
  while (cursor < bytes.length) {
    final length = decodeVarint(bytes, cursor);
    if (length.bytesRead != 1) throw FormatException('malformed varint length');
    cursor += length.bytesRead;
    final end = cursor + length.value;
    if (end > bytes.length) throw const FormatException('truncated envelope');
    final document = jsonDecode(utf8.decode(bytes.sublist(cursor, end)));
    messages.add(Message.fromJson(document as Map<String, dynamic>));
    cursor = end;
  }
  return messages;
}
