export function parseSetCookie(value) {
  if (typeof value !== 'string' || value.trim() === '') {
    throw new TypeError('Set-Cookie must be a non-empty string');
  }
  const parts = value.split(';').map((part) => part.trim());
  const separator = parts[0].indexOf('=');
  if (separator <= 0) {
    throw new TypeError('cookie pair is invalid');
  }
  const cookie = {
    name: parts[0].slice(0, separator),
    value: parts[0].slice(separator + 1),
    domain: null,
    path: '/',
    secure: false,
    maxAge: null
  };
  for (const attribute of parts.slice(1)) {
    const [rawName, ...rawValue] = attribute.split('=');
    const name = rawName.toLowerCase();
    const detail = rawValue.join('=').trim();
    if (name === 'domain' && detail.startsWith('.')) {
      cookie.domain = detail.slice(1).toLowerCase();
    } else if (name === 'domain') {
      cookie.domain = detail.toLowerCase();
    }
    if (name === 'path' && detail.startsWith('/')) {
      cookie.path = detail;
    } else if (name === 'path') {
      cookie.path = '/';
    }
    if (name === 'secure') {
      cookie.secure = true;
    }
    if (name === 'max-age' && Number.isInteger(detail)) {
      const seconds = Number(detail);
      if (seconds) cookie.maxAge = seconds;
    } else if (name === 'max-age') {
      cookie.maxAge = null;
    }
  }
  return cookie;
}
