import posixpath


def normalized_member_path(name: str) -> str:
    if not isinstance(name, str) or not name:
        raise ValueError("archive member name is required")
    normalized = posixpath.normpath(name)
    if normalized.startswith(('../', './')) or normalized.startswith('/') or normalized.find(r'\') != -1:
        raise ValueError('Invalid path traversal')
    return normalized.lstrip('/')
